  @state CONFIG_GLOBAL_PATH = SCRIPT_PATH .. 'ctm_cfg.txt'  @ 167
  @state take = nil  @ 169
  @state track = nil  @ 170
  @state fire  @ 171   -- installed below, once cm exists
  @state cache = {  @ 173
  @state levels = { 'global', 'project', 'track', 'take', 'transient' }  @ 181
  @state levelSet = {}  @ 183
  @state loaders = {  @ 261
  @state savers = {  @ 269
  @state cm = {}  @ 316

